              {todo.text}
            </span>
            <button onClick={() => dispatch({ type: 'DELETE_TODO', payload: todo.id })}>
              Delete
            </button>
          </li>
        ))}
      </ul>

      <p>{state.todos.filter(t => !t.completed).length} items left</p>
    </div>
  );
}

// Form reducer example
const formReducer = (state, action) => {
  switch (action.type) {
    case 'CHANGE':
      return {
        ...state,
        [action.field]: action.value,
        errors: {
          ...state.errors,
          [action.field]: validateField(action.field, action.value)
        }
      };
    case 'TOUCH':
      return {
        ...state,
        touched: { ...state.touched, [action.field]: true }
      };
    case 'SUBMIT':
      return {
        ...state,
        isSubmitting: true
      };
    case 'SUCCESS':
      return {
        ...state,
        isSubmitting: false,
        submitted: true
      };
    case 'ERROR':
      return {
        ...state,
        isSubmitting: false,
        submitError: action.error
      };
    case 'RESET':
      return action.initialState;
    default:
      return state;
  }
};

function validateField(field, value) {
  switch (field) {
    case 'email':
      return !value ? 'Email is required' :
             !/\S+@\S+\.\S+/.test(value) ? 'Invalid email' : '';
    case 'password':
      return !value ? 'Password is required' :
             value.length < 6 ? 'Password must be at least 6 characters' : '';
    default:
      return '';
  }
}

function LoginForm() {
  const initialState = {
    email: '',
    password: '',
    errors: { email: '', password: '' },
    touched: {},
    isSubmitting: false,
    submitted: false,
    submitError: ''
  };

  const [state, dispatch] = useReducer(formReducer, initialState);

  const handleChange = (field, value) => {
    dispatch({ type: 'CHANGE', field, value });
  };

  const handleBlur = (field) => {
    dispatch({ type: 'TOUCH', field });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    dispatch({ type: 'SUBMIT' });

    try {
      await login(state.email, state.password);
      dispatch({ type: 'SUCCESS' });
    } catch (error) {
      dispatch({ type: 'ERROR', error: error.message });
    }
  };

  if (state.submitted) {
    return <div>Login successful!</div>;
  }

  return (
    <form onSubmit={handleSubmit}>
      <div>
        <input
          type="email"
          value={state.email}
          onChange={(e) => handleChange('email', e.target.value)}
          onBlur={() => handleBlur('email')}
          placeholder="Email"
        />
        {state.touched.email && state.errors.email && 
          <span style={{ color: 'red' }}>{state.errors.email}</span>}
      </div>

      <div>
        <input
          type="password"
          value={state.password}
          onChange={(e) => handleChange('password', e.target.value)}
          onBlur={() => handleBlur('password')}
          placeholder="Password"
        />
        {state.touched.password && state.errors.password && 
          <span style={{ color: 'red' }}>{state.errors.password}</span>}
      </div>

      {state.submitError && <div style={{ color: 'red' }}>{state.submitError}</div>}

      <button type="submit" disabled={state.isSubmitting}>
        {state.isSubmitting ? 'Logging in...' : 'Login'}
      </button>
    </form>
  );
}

